@namespace Lumeo
@implements IAsyncDisposable

@* Render the label, control and helper/error as ONE self-contained vertical block so the
   field never splays into a row when dropped in a flex / centered container. Standalone
   form-field structural fix. *@
<div class="@Cx.Merge("flex flex-col items-start", Cx.When(FullWidth, "w-full"))">
@if (Label is not null && !InsideFormField)
{
    <label class="text-sm font-medium leading-none">
        @Label
        @if (Required)
        {
            <span class="text-destructive ms-0.5">*</span>
        }
    </label>
}

@if (Variant == TimePickerVariant.Wheel)
{
    @* iOS-style wheel picker — hours + minutes (+ AM/PM if 12-hour).
       Seconds are not supported in the wheel variant. *@
    @* id/role/aria-describedby splat into TimeWheelPicker's AdditionalAttributes (it has no matching
       [Parameter]s for these) so the FormField <Label For> resolves to a real rendered element even on
       this trigger-less variant — the List branch's button gets the same EffectiveTriggerId. A <div
       role="group"> is not a "labelable" element though, so `label for` alone may not reliably announce
       it — also wire aria-labelledby straight at the FormField's <label> id when inside a field
       (Codex P2). Null outside a FormField, omitting the attribute. *@
    <TimeWheelPicker Value="@Value" ValueChanged="HandleWheelChanged"
                     Use24Hour="@Use24Hour" MinuteStep="@MinuteStep"
                     Culture="@Culture" Class="@Class"
                     id="@EffectiveTriggerId"
                     role="group"
                     aria-labelledby="@FormField?.LabelId"
                     aria-describedby="@FormFieldDescribedBy" />
}
else
{
<Popover @bind-Open="_isOpen" Class="@(FullWidth ? "w-full" : null)">
    <PopoverTrigger Class="@(FullWidth ? "w-full" : null)">
        <button type="button"
                id="@EffectiveTriggerId"
                name="@Name"
                aria-required="@Required.ToString().ToLower()"
                aria-invalid="@EffectiveInvalid.ToString().ToLower()"
                aria-describedby="@FormFieldDescribedBy"
                class="@CssClass"
                disabled="@Disabled"
                @attributes="EffectiveAttributes">
            <SvgGlyph Svg="@(LumeoIcons.Clock)" class="me-2 h-4 w-4 shrink-0" />
            @if (Value.HasValue)
            {
                <span>@FormatTime(Value.Value)</span>
            }
            else
            {
                <span class="text-muted-foreground group-hover:text-accent-foreground">@EffectivePlaceholder</span>
            }
        </button>
    </PopoverTrigger>
    <PopoverContent Align="Lumeo.Align.Start" Class="w-auto p-0">
        <div class="flex divide-x divide-border/40">
            @* Hours column *@
            <div id="@_hoursColId" role="listbox" aria-label="@L["TimePicker.HoursLabel"]" class="flex flex-col h-[200px] overflow-y-auto py-1 scrollbar-thin">
                @{ var hours = GetHours(); }
                @{ var hoursRoving = RovingValue(_hoursColId, hours); }
                @foreach (var hour in hours)
                {
                    var h = hour;
                    var isSelected = Value.HasValue && GetDisplayHour(Value.Value) == h;
                    var disabled = IsHourDisabled(h);
                    <button type="button" id="@ColItemId(_hoursColId, h)" role="option"
                            aria-selected="@(isSelected ? "true" : "false")"
                            tabindex="@(h == hoursRoving ? "0" : "-1")"
                            disabled="@disabled"
                            class="@ColItemClass(isSelected)"
                            @onclick="() => SelectHour(h)"
                            @onkeydown="e => HandleColumnKeyDown(e, _hoursColId, hours, h)">
                        @h.ToString("D2")
                    </button>
                }
            </div>

            @* Minutes column *@
            <div id="@_minutesColId" role="listbox" aria-label="@L["TimePicker.MinutesLabel"]" class="flex flex-col h-[200px] overflow-y-auto py-1 scrollbar-thin">
                @{ var minutes = GetMinutes(); }
                @{ var minutesRoving = RovingValue(_minutesColId, minutes); }
                @foreach (var minute in minutes)
                {
                    var m = minute;
                    var isSelected = Value.HasValue && Value.Value.Minutes == m;
                    var disabled = IsMinuteDisabled(m);
                    <button type="button" id="@ColItemId(_minutesColId, m)" role="option"
                            aria-selected="@(isSelected ? "true" : "false")"
                            tabindex="@(m == minutesRoving ? "0" : "-1")"
                            disabled="@disabled"
                            class="@ColItemClass(isSelected)"
                            @onclick="() => SelectMinute(m)"
                            @onkeydown="e => HandleColumnKeyDown(e, _minutesColId, minutes, m)">
                        @m.ToString("D2")
                    </button>
                }
            </div>

            @* Seconds column *@
            @if (ShowSeconds)
            {
                <div id="@_secondsColId" role="listbox" aria-label="@L["TimePicker.SecondsLabel"]" class="flex flex-col h-[200px] overflow-y-auto py-1 scrollbar-thin">
                    @{ var seconds = GetSeconds(); }
                    @{ var secondsRoving = RovingValue(_secondsColId, seconds); }
                    @foreach (var second in seconds)
                    {
                        var s = second;
                        var isSelected = Value.HasValue && Value.Value.Seconds == s;
                        var disabled = IsSecondDisabled(s);
                        <button type="button" id="@ColItemId(_secondsColId, s)" role="option"
                                aria-selected="@(isSelected ? "true" : "false")"
                                tabindex="@(s == secondsRoving ? "0" : "-1")"
                                disabled="@disabled"
                                class="@ColItemClass(isSelected)"
                                @onclick="() => SelectSecond(s)"
                                @onkeydown="e => HandleColumnKeyDown(e, _secondsColId, seconds, s)">
                            @s.ToString("D2")
                        </button>
                    }
                </div>
            }

            @* AM/PM column *@
            @if (!EffectiveUse24Hour)
            {
                <div class="flex flex-col py-1">
                    @{
                        var isAm = !Value.HasValue || Value.Value.Hours < 12;
                        var amLabel = string.IsNullOrEmpty(EffectiveCulture.DateTimeFormat.AMDesignator) ? "AM" : EffectiveCulture.DateTimeFormat.AMDesignator;
                        var pmLabel = string.IsNullOrEmpty(EffectiveCulture.DateTimeFormat.PMDesignator) ? "PM" : EffectiveCulture.DateTimeFormat.PMDesignator;
                    }
                    <button type="button"
                            aria-pressed="@(isAm ? "true" : "false")"
                            class="@ColItemClass(isAm)"
                            @onclick="() => SelectAmPm(true)">
                        @amLabel
                    </button>
                    <button type="button"
                            aria-pressed="@(!isAm ? "true" : "false")"
                            class="@ColItemClass(!isAm)"
                            @onclick="() => SelectAmPm(false)">
                        @pmLabel
                    </button>
                </div>
            }
        </div>
    </PopoverContent>
</Popover>
}

@if (!InsideFormField)
{
    @if (EffectiveInvalid && ErrorText is not null)
    {
        <p class="text-xs text-destructive">@ErrorText</p>
    }
    else if (HelperText is not null)
    {
        <p class="text-xs text-muted-foreground">@HelperText</p>
    }
}
</div>

@inject Lumeo.Services.Localization.ILumeoLocalizer L
@inject IComponentInteropService Interop

@code {
    /// <summary>
    /// Visual style of the picker. <see cref="TimePickerVariant.List"/> renders the
    /// existing scrollable hour/minute columns inside a popover (default).
    /// <see cref="TimePickerVariant.Wheel"/> renders inline iOS-style snap-scrolling
    /// columns. The Wheel variant doesn't show seconds.
    /// </summary>
    public enum TimePickerVariant { List, Wheel }

    [Parameter] public TimePickerVariant Variant { get; set; } = TimePickerVariant.List;

    [CascadingParameter] private FormField.FormFieldContext? FormField { get; set; }

    [Parameter] public bool Required { get; set; }
    [Parameter] public bool Invalid { get; set; }
    [Parameter] public string? ErrorText { get; set; }
    [Parameter] public string? HelperText { get; set; }
    [Parameter] public string? Label { get; set; }
    [Parameter] public string? Name { get; set; }

    private bool EffectiveInvalid => Invalid || FormField?.HasError == true;
    private bool InsideFormField => FormField is not null;

    // Inside a FormField, adopt its generated ControlId so the field's <Label For>
    // resolves to the rendered trigger (click-to-focus + association). Null outside
    // a FormField — EffectiveTriggerId then falls back to the generated _triggerId.
    // The empty guard avoids id="" when no id was generated.
    private string? FormFieldControlId => string.IsNullOrEmpty(FormField?.ControlId) ? null : FormField!.ControlId;
    private string? FormFieldDescribedBy => FormField?.DescribedBy;

    // The id actually rendered on the focusable trigger (the List-variant popover
    // button). Any interop that focuses or anchors the trigger MUST use this same
    // value so focus/anchoring target the rendered element. _triggerId stays as the
    // fallback when not inside a FormField.
    private readonly string _triggerId = LumeoIds.New("time-picker-trigger");
    private string EffectiveTriggerId => FormFieldControlId ?? _triggerId;

    // Inside a FormField the generated id must own this element so the FormField <Label For> (and any
    // interop keyed off the id) stays valid; a consumer-splatted id in AdditionalAttributes renders after
    // the explicit id= and would override it. Strip it here when InsideFormField; outside, pass through.
    private Dictionary<string, object>? EffectiveAttributes =>
        InsideFormField && AdditionalAttributes?.ContainsKey("id") == true
            ? AdditionalAttributes.Where(kv => kv.Key != "id").ToDictionary(kv => kv.Key, kv => kv.Value)
            : AdditionalAttributes;

    [Parameter] public TimeSpan? Value { get; set; }
    [Parameter] public EventCallback<TimeSpan?> ValueChanged { get; set; }
    /// <summary>
    /// When <c>true</c> renders a 24-hour clock; when <c>false</c> renders 12-hour with AM/PM.
    /// When <c>null</c> (default) the picker derives the choice from
    /// <see cref="EffectiveCulture"/>'s <c>ShortTimePattern</c> — <c>de-DE</c>, <c>fr-FR</c>
    /// and similar see 24-hour; <c>en-US</c> sees 12-hour.
    /// </summary>
    [Parameter] public bool? Use24Hour { get; set; }
    [Parameter] public bool ShowSeconds { get; set; }
    [Parameter] public int MinuteStep { get; set; } = 1;
    [Parameter] public int SecondStep { get; set; } = 1;

    /// <summary>Earliest selectable time (inclusive). Times before this are
    /// rendered as disabled options. Null (default) means no lower bound.</summary>
    [Parameter] public TimeSpan? Min { get; set; }
    /// <summary>Latest selectable time (inclusive). Times after this are
    /// rendered as disabled options. Null (default) means no upper bound.</summary>
    [Parameter] public TimeSpan? Max { get; set; }

    [Parameter] public string? Placeholder { get; set; }

    /// <summary>
    /// Overrides <see cref="System.Globalization.CultureInfo.CurrentCulture"/> for
    /// 24h/12h detection and AM/PM designators. Leave null to honour ASP.NET request localization.
    /// </summary>
    [Parameter] public System.Globalization.CultureInfo? Culture { get; set; }

    private System.Globalization.CultureInfo EffectiveCulture => Culture ?? System.Globalization.CultureInfo.CurrentCulture;
    // Per CLDR/.NET conventions a lowercase "h" in the short-time pattern means 12-hour;
    // uppercase "H" means 24-hour. We honour an explicit Use24Hour first, then derive.
    private bool EffectiveUse24Hour => Use24Hour ?? !EffectiveCulture.DateTimeFormat.ShortTimePattern.Contains('h');

    private string EffectivePlaceholder => Placeholder ?? L["TimePicker.Placeholder"];
    [Parameter] public bool Disabled { get; set; }
    /// <summary>Per-picker density override. When null, inherits from any
    /// ancestor <see cref="DensityScope"/>; if neither is set, matches the
    /// historical <c>Comfortable</c> default. Only the trigger height +
    /// horizontal padding shift between values.</summary>
    [Parameter] public Density? Density { get; set; }
    [CascadingParameter] private Density? InheritedDensity { get; set; }
    [Parameter] public string? Class { get; set; }
    /// <summary>
    /// When <c>true</c>, the time picker expands to fill its container width —
    /// equivalent to <c>FullWidth</c> on a <see cref="Button"/>. Propagates
    /// <c>w-full</c> to the Popover wrapper, PopoverTrigger, and the trigger
    /// button so the constraint reaches the rendered element through the
    /// shrink-wrap chain.
    /// </summary>
    [Parameter] public bool FullWidth { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _isOpen;

    // Per-column ids so the arrow-key list navigation can move DOM focus
    // between option buttons (each button id is "{colId}-{value}").
    private readonly string _hoursColId = LumeoIds.New("tp-hours");
    private readonly string _minutesColId = LumeoIds.New("tp-minutes");
    private readonly string _secondsColId = LumeoIds.New("tp-seconds");

    private static string ColItemId(string colId, int value) => $"{colId}-{value}";

    private static string ColItemClass(bool isSelected) =>
        isSelected
            ? "px-3 py-1.5 text-sm cursor-pointer bg-primary text-primary-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 disabled:pointer-events-none disabled:opacity-40"
            : "px-3 py-1.5 text-sm cursor-pointer hover:bg-muted/50 focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 focus-visible:bg-muted/50 disabled:pointer-events-none disabled:opacity-40";

    // ---- Min/Max enforcement ----
    // An hour is disabled when its whole [h:00..h:59(:59)] band lies outside
    // [Min, Max]. A minute/second is disabled when the time it would produce
    // (with the rest of the current selection) falls outside the bounds. The
    // 12-hour hour column carries display hours (1..12); convert to the 24-hour
    // value using the current AM/PM before bounds-checking.
    private bool IsHourDisabled(int displayHour)
    {
        var h24 = DisplayHourTo24(displayHour);
        // Highest time in this hour we could ever pick (seconds optional).
        var hourEnd = new TimeSpan(0, h24, 59, ShowSeconds ? 59 : 0);
        var hourStart = new TimeSpan(h24, 0, 0);
        if (Min.HasValue && hourEnd < Min.Value) return true;
        if (Max.HasValue && hourStart > Max.Value) return true;
        return false;
    }

    private bool IsMinuteDisabled(int minute)
    {
        var h = (Value ?? TimeSpan.Zero).Hours;
        var minStart = new TimeSpan(0, h, minute, 0);
        var minEnd = new TimeSpan(0, h, minute, ShowSeconds ? 59 : 0);
        if (Min.HasValue && minEnd < Min.Value) return true;
        if (Max.HasValue && minStart > Max.Value) return true;
        return false;
    }

    private bool IsSecondDisabled(int second)
    {
        var current = Value ?? TimeSpan.Zero;
        var candidate = new TimeSpan(0, current.Hours, current.Minutes, second);
        if (Min.HasValue && candidate < Min.Value) return true;
        if (Max.HasValue && candidate > Max.Value) return true;
        return false;
    }

    private int DisplayHourTo24(int displayHour)
    {
        if (EffectiveUse24Hour) return displayHour;
        // With no value chosen yet, AM/PM is ambiguous. Defaulting to AM would
        // disable every hour when Min is a PM time (e.g. 14:00). Infer per-hour
        // from the allowed range and prefer PM only when AM is out of bounds.
        if (Value is null)
        {
            var min = Min;
            var max = Max;
            var amHour = displayHour % 12;
            var pmHour = amHour + 12;
            var amInBounds = (!min.HasValue || new TimeSpan(amHour, 59, 59) >= min.Value)
                          && (!max.HasValue || new TimeSpan(amHour, 0, 0) <= max.Value);
            var pmInBounds = (!min.HasValue || new TimeSpan(pmHour, 59, 59) >= min.Value)
                          && (!max.HasValue || new TimeSpan(pmHour, 0, 0) <= max.Value);
            return (!amInBounds && pmInBounds) ? pmHour : amHour;
        }
        var isPm = Value.Value.Hours >= 12;
        var h = displayHour % 12;
        return isPm ? h + 12 : h;
    }

    // ---- Arrow-key list navigation (roving focus per column) ----
    // ArrowDown/Up move to the next/previous ENABLED option, Home/End jump to
    // the first/last enabled option, Enter/Space select. Page scroll for the
    // arrow keys is suppressed via the prevent-default-keys registration below.
    private async Task HandleColumnKeyDown(KeyboardEventArgs e, string colId, List<int> values, int current)
    {
        switch (e.Key)
        {
            case "ArrowDown": await FocusAdjacent(colId, values, current, +1); break;
            case "ArrowUp": await FocusAdjacent(colId, values, current, -1); break;
            case "Home": await FocusEdge(colId, values, fromStart: true); break;
            case "End": await FocusEdge(colId, values, fromStart: false); break;
            // Enter/Space are intentionally NOT handled here: each option is a native <button> with an
            // @onclick, so Enter/Space already activate it (the browser synthesizes a click → SelectHour/
            // Minute/Second). Handling them here too would fire the selection — and ValueChanged — twice
            // (Codex P3). Arrow/Home/End only move the roving focus.
        }
    }

    private async Task FocusAdjacent(string colId, List<int> values, int current, int step)
    {
        var idx = values.IndexOf(current);
        if (idx < 0) return;
        for (var i = idx + step; i >= 0 && i < values.Count; i += step)
        {
            if (!IsColItemDisabled(colId, values[i]))
            {
                await Interop.FocusElement(ColItemId(colId, values[i]));
                return;
            }
        }
    }

    private async Task FocusEdge(string colId, List<int> values, bool fromStart)
    {
        var ordered = fromStart ? values : Enumerable.Reverse(values).ToList();
        foreach (var v in ordered)
        {
            if (!IsColItemDisabled(colId, v))
            {
                await Interop.FocusElement(ColItemId(colId, v));
                return;
            }
        }
    }

    private bool IsColItemDisabled(string colId, int value)
    {
        if (colId == _hoursColId) return IsHourDisabled(value);
        if (colId == _minutesColId) return IsMinuteDisabled(value);
        if (colId == _secondsColId) return IsSecondDisabled(value);
        return false;
    }

    private bool IsColItemSelected(string colId, int value)
    {
        if (!Value.HasValue) return false;
        if (colId == _hoursColId) return GetDisplayHour(Value.Value) == value;
        if (colId == _minutesColId) return Value.Value.Minutes == value;
        if (colId == _secondsColId) return Value.Value.Seconds == value;
        return false;
    }

    // The single tabbable ("roving root") option value for a column. When an
    // ENABLED option is selected it stays the tab stop (existing behaviour). When
    // nothing is selected — or the selection has since become disabled (e.g. Min/Max
    // moved past it) — the first ENABLED option becomes the tab stop so the column
    // keeps a keyboard entry point. A disabled button can never hold focus, so it must
    // not be seeded as the tab stop or the column would lose its tab entry entirely.
    // Returns int.MinValue (matches no rendered option) when every option is disabled.
    private int RovingValue(string colId, List<int> values)
    {
        foreach (var v in values)
        {
            if (IsColItemSelected(colId, v) && !IsColItemDisabled(colId, v)) return v;
        }
        foreach (var v in values)
        {
            if (!IsColItemDisabled(colId, v)) return v;
        }
        return int.MinValue;
    }

    // Suppress page / column scroll for the arrow keys while the list popover
    // is open so the first ArrowUp/Down moves focus without also scrolling the
    // overflow column (same pattern as Calendar's day grid). Only relevant to
    // the List variant — the Wheel variant manages its own scroll snapping.
    private bool _navKeysRegistered;
    private static readonly PreventDefaultKeyRule[] ColumnNavKeys =
    [
        new("ArrowUp"), new("ArrowDown"), new("Home"), new("End"),
    ];

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (Variant != TimePickerVariant.List) return;

        if (_isOpen && !_navKeysRegistered)
        {
            _navKeysRegistered = true;
            try
            {
                await Interop.RegisterPreventDefaultKeys(_hoursColId, ColumnNavKeys);
                await Interop.RegisterPreventDefaultKeys(_minutesColId, ColumnNavKeys);
                if (ShowSeconds) await Interop.RegisterPreventDefaultKeys(_secondsColId, ColumnNavKeys);
            }
            catch (JSDisconnectedException) { _navKeysRegistered = false; }
            catch (InvalidOperationException) { _navKeysRegistered = false; } // prerender
        }
        else if (!_isOpen && _navKeysRegistered)
        {
            _navKeysRegistered = false;
            await UnregisterNavKeys();
        }
    }

    private async Task UnregisterNavKeys()
    {
        try
        {
            await Interop.UnregisterPreventDefaultKeys(_hoursColId);
            await Interop.UnregisterPreventDefaultKeys(_minutesColId);
            // Seconds column is only registered when ShowSeconds is set, so only
            // unregister it then (mirrors the registration guard).
            if (ShowSeconds) await Interop.UnregisterPreventDefaultKeys(_secondsColId);
        }
        // DisposeAsync routes through here; a mid-navigation dispose can surface
        // ObjectDisposed/InvalidOperation from the JS layer — swallow all three.
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }

    public async ValueTask DisposeAsync()
    {
        if (_navKeysRegistered) await UnregisterNavKeys();
    }

    private Lumeo.Density EffectiveDensity => Density ?? InheritedDensity ?? Lumeo.Density.Comfortable;

    // Trigger height + horizontal padding track density; Comfortable
    // reproduces the historical `h-9 px-3`.
    private string SizeClasses => EffectiveDensity switch
    {
        Lumeo.Density.Compact => "h-8 px-2.5 py-1",
        Lumeo.Density.Spacious => "h-10 px-4 py-2.5",
        _ => "h-9 px-3 py-2"
    };

    private string CssClass => Cx.Merge("group flex", SizeClasses, Cx.When(FullWidth, "w-full"), "items-center rounded-md border", (EffectiveInvalid ? "border-destructive ring-1 ring-destructive/20" : "border-input"), "bg-transparent text-sm shadow-sm hover:bg-accent hover:text-accent-foreground disabled:cursor-not-allowed disabled:opacity-50", Class);

    private string FormatTime(TimeSpan time)
    {
        if (EffectiveUse24Hour)
        {
            return ShowSeconds
                ? $"{time.Hours:D2}:{time.Minutes:D2}:{time.Seconds:D2}"
                : $"{time.Hours:D2}:{time.Minutes:D2}";
        }
        else
        {
            var hour12 = time.Hours % 12;
            if (hour12 == 0) hour12 = 12;
            var dtf = EffectiveCulture.DateTimeFormat;
            var ampm = time.Hours < 12
                ? (string.IsNullOrEmpty(dtf.AMDesignator) ? "AM" : dtf.AMDesignator)
                : (string.IsNullOrEmpty(dtf.PMDesignator) ? "PM" : dtf.PMDesignator);
            return ShowSeconds
                ? $"{hour12:D2}:{time.Minutes:D2}:{time.Seconds:D2} {ampm}"
                : $"{hour12:D2}:{time.Minutes:D2} {ampm}";
        }
    }

    private List<int> GetHours()
    {
        var hours = new List<int>();
        if (EffectiveUse24Hour)
        {
            for (var i = 0; i < 24; i++) hours.Add(i);
        }
        else
        {
            for (var i = 1; i <= 12; i++) hours.Add(i);
        }
        return hours;
    }

    private int GetDisplayHour(TimeSpan time)
    {
        if (EffectiveUse24Hour) return time.Hours;
        var h = time.Hours % 12;
        return h == 0 ? 12 : h;
    }

    private List<int> GetMinutes()
    {
        var minutes = new List<int>();
        var step = Math.Max(1, MinuteStep);
        for (var i = 0; i < 60; i += step) minutes.Add(i);
        return minutes;
    }

    private List<int> GetSeconds()
    {
        var seconds = new List<int>();
        var step = Math.Max(1, SecondStep);
        for (var i = 0; i < 60; i += step) seconds.Add(i);
        return seconds;
    }

    private async Task SelectHour(int hour)
    {
        if (IsHourDisabled(hour)) return;
        var current = Value ?? TimeSpan.Zero;
        // Resolve AM/PM the SAME way IsHourDisabled does (via DisplayHourTo24).
        // When Value is null the enable check infers the AM/PM that keeps the
        // hour in [Min, Max]; recomputing isPm from the zero default here would
        // disagree and let an out-of-bounds AM time commit (e.g. Min=14:00 enables
        // display-hour 2 as PM but a naive AM commit would store 02:00).
        var actualHour = DisplayHourTo24(hour);
        var newValue = new TimeSpan(actualHour, current.Minutes, current.Seconds);
        // Defence in depth: never commit outside the bounds even if the enable
        // check and this resolution ever diverge.
        if ((Min.HasValue && newValue < Min.Value) || (Max.HasValue && newValue > Max.Value)) return;
        Value = newValue;
        await ValueChanged.InvokeAsync(newValue);
    }

    private async Task SelectMinute(int minute)
    {
        if (IsMinuteDisabled(minute)) return;
        var current = Value ?? TimeSpan.Zero;
        var newValue = new TimeSpan(current.Hours, minute, current.Seconds);
        Value = newValue;
        await ValueChanged.InvokeAsync(newValue);
    }

    private async Task SelectSecond(int second)
    {
        if (IsSecondDisabled(second)) return;
        var current = Value ?? TimeSpan.Zero;
        var newValue = new TimeSpan(current.Hours, current.Minutes, second);
        Value = newValue;
        await ValueChanged.InvokeAsync(newValue);
    }

    private async Task HandleWheelChanged(TimeSpan? newValue)
    {
        Value = newValue;
        await ValueChanged.InvokeAsync(newValue);
    }

    private async Task SelectAmPm(bool isAm)
    {
        var current = Value ?? TimeSpan.Zero;
        var hour = current.Hours % 12;
        if (!isAm) hour += 12;
        var newValue = new TimeSpan(hour, current.Minutes, current.Seconds);
        // The AM/PM buttons carry no per-option disabled gate, so guard the
        // commit directly: flipping into a half-day that lies outside [Min, Max]
        // must not change the value.
        if ((Min.HasValue && newValue < Min.Value) || (Max.HasValue && newValue > Max.Value)) return;
        Value = newValue;
        await ValueChanged.InvokeAsync(newValue);
    }
}

@namespace Lumeo
@using System.Globalization
@using Lumeo.Internal
@implements IDisposable

<div class="@RootCssClass" @attributes="AdditionalAttributes" style="@RootStyle">
    @* Center selection indicator *@
    <div class="absolute start-0 end-0 top-1/2 -translate-y-1/2 h-10 border-y border-primary/30 pointer-events-none"></div>

    @* Hours column *@
    <div class="flex-1 overflow-y-scroll snap-y snap-mandatory scrollbar-none h-full"
         @onscroll="OnHourScroll"
         @ref="_hourCol">
        <div class="h-[60px]"></div>
        @foreach (var h in _hours)
        {
            var hour = h;
            <div class="h-10 flex items-center justify-center snap-center text-base select-none @(hour == _hour ? "text-primary font-semibold" : "text-muted-foreground")">
                @hour.ToString("D2")
            </div>
        }
        <div class="h-[60px]"></div>
    </div>

    @* Minutes column *@
    <div class="flex-1 overflow-y-scroll snap-y snap-mandatory scrollbar-none h-full"
         @onscroll="OnMinuteScroll"
         @ref="_minuteCol">
        <div class="h-[60px]"></div>
        @foreach (var m in _minutes)
        {
            var minute = m;
            <div class="h-10 flex items-center justify-center snap-center text-base select-none @(minute == _minute ? "text-primary font-semibold" : "text-muted-foreground")">
                @minute.ToString("D2")
            </div>
        }
        <div class="h-[60px]"></div>
    </div>

    @* AM/PM column (12-hour only) *@
    @if (!EffectiveUse24Hour)
    {
        <div class="flex-1 overflow-y-scroll snap-y snap-mandatory scrollbar-none h-full"
             @onscroll="OnPeriodScroll"
             @ref="_periodCol">
            <div class="h-[60px]"></div>
            @for (var p = 0; p < 2; p++)
            {
                var period = p;
                var label = period == 0 ? _amLabel : _pmLabel;
                <div class="h-10 flex items-center justify-center snap-center text-base select-none @(period == _periodIndex ? "text-primary font-semibold" : "text-muted-foreground")">
                    @label
                </div>
            }
            <div class="h-[60px]"></div>
        </div>
    }
</div>

@inject Lumeo.Services.IComponentInteropService Interop

@code {
    // --- Public API ----------------------------------------------------------
    [Parameter] public TimeSpan? Value { get; set; }
    [Parameter] public EventCallback<TimeSpan?> ValueChanged { get; set; }
    /// <summary>
    /// When <c>true</c> renders a 24-hour clock; when <c>false</c> renders 12-hour with AM/PM.
    /// When <c>null</c> (default), derived from <c>CultureInfo.DateTimeFormat.ShortTimePattern</c>.
    /// </summary>
    [Parameter] public bool? Use24Hour { get; set; }
    [Parameter] public int MinuteStep { get; set; } = 1;
    [Parameter] public CultureInfo? Culture { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // --- Layout constants ----------------------------------------------------
    private const int ItemHeight = 40;
    private const int Height = 160;

    // --- Element refs --------------------------------------------------------
    private ElementReference _hourCol;
    private ElementReference _minuteCol;
    private ElementReference _periodCol;

    // --- Selection state -----------------------------------------------------
    private int _hour = 0;           // display hour (0-23 or 1-12)
    private int _minute = 0;
    private int _periodIndex = 0;    // 0=AM, 1=PM (only relevant when !Use24Hour)
    private List<int> _hours = new();
    private List<int> _minutes = new();
    private string _amLabel = "AM";
    private string _pmLabel = "PM";

    private const int SnapDebounceMs = 100;
    private readonly DebouncedValue<int> _hourDebounced = new(SnapDebounceMs);
    private readonly DebouncedValue<int> _minuteDebounced = new(SnapDebounceMs);
    private readonly DebouncedValue<int> _periodDebounced = new(SnapDebounceMs);
    private bool _initialised;
    // External-change resync — see DateWheelPicker for the rationale: columns
    // are scroll-positioned only programmatically, so a Value change from
    // outside must re-scroll them or the next user scroll commits from stale
    // offsets. Tracks the last incoming Value seen; consulted by the
    // null-Value path of OnParametersSet's resync gate below (both controlled-
    // but-unsupplied and uncontrolled use — see _ownLastEmitted).
    private TimeSpan? _lastSyncedValue;
    // CONTROLLED discriminator (controlled-component rollback fix): the last
    // value RaiseChange pushed UP via ValueChanged — also re-synced whenever
    // OnParametersSet adopts an authoritative non-null Value. A controlled
    // parent re-render that echoes back this exact value is an accepted commit
    // (we're already positioned there from the user's own scroll, no resync
    // needed); any OTHER non-null Value — including the parent VETOING by
    // re-rendering with its prior value unchanged — is an authoritative
    // assertion and must win, re-scrolling the columns back to it.
    // Battle-wave2 #68 (state-on-data-change): also doubles as the seed
    // fallback for controlled-but-unsupplied use, where a delegate is attached
    // purely to observe commits without writing Value back, so it stays null.
    // Without this, OnParametersSet saw `null != _lastSyncedValue` (which
    // RaiseChange had set to the committed time), treated it as an external
    // clear, and reseeded the columns back to 00:00 — wiping the user's
    // selection. We remember our own last emission so a "Value came back
    // unchanged-as-null" re-render is NOT mistaken for an external resync, and
    // so the seed falls back to the committed selection rather than
    // TimeSpan.Zero. (A null Value carries no authoritative assertion of its
    // own, so while it stays null we fall back to the same "differs from last
    // incoming" check as fully uncontrolled use.)
    private TimeSpan? _ownLastEmitted;
    private bool _resyncPending;

    private CultureInfo EffectiveCulture => Culture ?? CultureInfo.CurrentCulture;
    // Mirror TimePicker's derivation: lowercase "h" in ShortTimePattern = 12-hour.
    private bool EffectiveUse24Hour => Use24Hour ?? !EffectiveCulture.DateTimeFormat.ShortTimePattern.Contains('h');

    private string RootCssClass => Cx.Merge("flex gap-2 relative", Class);
    private string RootStyle => $"height: {Height}px;";

    protected override void OnParametersSet()
    {
        var dtf = EffectiveCulture.DateTimeFormat;
        _amLabel = string.IsNullOrEmpty(dtf.AMDesignator) ? "AM" : dtf.AMDesignator;
        _pmLabel = string.IsNullOrEmpty(dtf.PMDesignator) ? "PM" : dtf.PMDesignator;

        _hours = EffectiveUse24Hour
            ? Enumerable.Range(0, 24).ToList()
            : Enumerable.Range(1, 12).ToList();

        var step = Math.Max(1, MinuteStep);
        _minutes = new List<int>();
        for (var i = 0; i < 60; i += step) _minutes.Add(i);

        if (ValueChanged.HasDelegate)
        {
            // CONTROLLED: the parent owns Value. A non-null Value is always an
            // authoritative assertion — echo of our own push (Value ==
            // _ownLastEmitted) needs no re-scroll; anything else, INCLUDING the
            // parent VETOING a commit by re-rendering with its prior value
            // unchanged, is authoritative and must win. (Requiring it to ALSO
            // differ from the last INCOMING Value — the pre-fix check — is what
            // let a veto slip through: the pre- and post-veto Value are the
            // same literal, so that comparison never re-fired even though this
            // one does.) A null Value carries no assertion of its own — some
            // controlled consumers attach ValueChanged purely to observe
            // commits without writing back (#68) — so while Value stays null
            // we fall back to the same "differs from last incoming" check as
            // uncontrolled use.
            if (Value.HasValue)
            {
                if (Value != _ownLastEmitted)
                {
                    _lastSyncedValue = Value;
                    _ownLastEmitted = Value;
                    _resyncPending = true;
                }
                else
                {
                    // Accepted echo — already positioned, so no resync is needed, but
                    // _lastSyncedValue must still track the TRUE authoritative Value (not just the
                    // resync cases). Without this, a LATER genuine clear-to-null couldn't tell "Value
                    // demonstrably HAD a value" from the #68 "Value has always been null" ambiguity
                    // (round-17 Codex follow-up to the round-16 fix above): _lastSyncedValue would
                    // still read null even though the parent's accepted commit made Value real.
                    _lastSyncedValue = Value;
                }
            }
            else if (Value != _lastSyncedValue)
            {
                // A GENUINE, distinguishable change to null: _lastSyncedValue was non-null on the
                // previous render, so this is NOT the #68 "Value has always been null" observer-only
                // ambiguity (where there is nothing to distinguish a deliberate clear from "hasn't
                // propagated yet" — that case intentionally falls through unchanged below, preserving
                // #68's keep-the-local-commit behavior). Here the parent demonstrably HAD a value and
                // now demonstrably doesn't — an authoritative clear/veto — so also reset
                // _ownLastEmitted, or the seed fallback on line ~193 would keep showing the rejected
                // optimistic commit instead of resetting (Codex P2).
                if (_lastSyncedValue.HasValue) _ownLastEmitted = null;
                _lastSyncedValue = Value;
                _resyncPending = true;
            }
        }
        else if (Value != _lastSyncedValue && Value != _ownLastEmitted)
        {
            // UNCONTROLLED: component owns the live selection (#68) — adopt the
            // parameter only when the parent genuinely changes it; a parent
            // re-render that echoes Value back as null after our own commit
            // must not reseed the columns to zero.
            _lastSyncedValue = Value;
            _resyncPending = true;
        }

        // Seed from the parent's Value when supplied; otherwise fall back to our own
        // committed selection (uncontrolled use) before the TimeSpan.Zero default, so
        // a parent re-render that leaves Value null preserves the user's pick. (#68)
        var seed = Value ?? _ownLastEmitted ?? TimeSpan.Zero;
        if (EffectiveUse24Hour)
        {
            _hour = seed.Hours;
        }
        else
        {
            var h12 = seed.Hours % 12;
            _hour = h12 == 0 ? 12 : h12;
            _periodIndex = seed.Hours >= 12 ? 1 : 0;
        }
        // Snap the seeded minute to the closest step.
        _minute = SnapMinute(seed.Minutes);
    }

    private int SnapMinute(int minute)
    {
        if (_minutes.Count == 0) return 0;
        var nearest = _minutes[0];
        var bestDiff = Math.Abs(minute - nearest);
        foreach (var m in _minutes)
        {
            var d = Math.Abs(minute - m);
            if (d < bestDiff) { bestDiff = d; nearest = m; }
        }
        return nearest;
    }

    // --- Scroll handlers -----------------------------------------------------
    private async Task OnHourScroll()
    {
        if (!_initialised) return;
        var idx = await GetIndexAsync(_hourCol);
        if (idx < 0 || idx >= _hours.Count) return;
        _hourDebounced.Set(_hours[idx]);
    }

    private async Task OnMinuteScroll()
    {
        if (!_initialised) return;
        var idx = await GetIndexAsync(_minuteCol);
        if (idx < 0 || idx >= _minutes.Count) return;
        _minuteDebounced.Set(_minutes[idx]);
    }

    private async Task OnPeriodScroll()
    {
        if (!_initialised) return;
        var idx = await GetIndexAsync(_periodCol);
        if (idx < 0 || idx > 1) return;
        _periodDebounced.Set(idx);
    }

    private async Task<int> GetIndexAsync(ElementReference el)
    {
        var scrollTop = await Interop.WheelScrollTop(el);
        return (int)Math.Round(scrollTop / ItemHeight);
    }

    protected override void OnInitialized()
    {
        _hourDebounced.OnChanged(pending => InvokeAsync(async () =>
        {
            if (pending == _hour) return;
            _hour = pending;
            await RaiseChange();
            StateHasChanged();
        }));
        _minuteDebounced.OnChanged(pending => InvokeAsync(async () =>
        {
            if (pending == _minute) return;
            _minute = pending;
            await RaiseChange();
            StateHasChanged();
        }));
        _periodDebounced.OnChanged(pending => InvokeAsync(async () =>
        {
            if (pending == _periodIndex) return;
            _periodIndex = pending;
            await RaiseChange();
            StateHasChanged();
        }));
    }

    private async Task RaiseChange()
    {
        int hour24;
        if (EffectiveUse24Hour)
        {
            hour24 = _hour;
        }
        else
        {
            var h = _hour % 12;
            hour24 = _periodIndex == 1 ? h + 12 : h;
        }
        var t = new TimeSpan(hour24, _minute, 0);
        // Our own commit — the parent echoing it back (controlled use) or never
        // adopting it (uncontrolled, Value stays null, see #68) is NOT an external
        // change. Record it as _ownLastEmitted; OnParametersSet's resync gate skips
        // any incoming Value equal to it, and the seed falls back to it when Value is
        // null, so neither echo nor non-adoption reseeds the columns to zero. We do
        // NOT pre-set _lastSyncedValue here: leaving it lagging the parent's last
        // supplied value is what lets the uncontrolled `null != _lastSyncedValue`
        // check read false on the follow-up re-render.
        _ownLastEmitted = t;
        await ValueChanged.InvokeAsync(t);
    }

    // Test seam (state-on-data-change #68): drives a deterministic self-commit to a
    // specific time, mirroring what the debounced scroll handlers do when the user
    // settles each column. The real scroll path depends on JS scroll offsets +
    // timer debounce, which are not reproducible in bUnit; this exercises the same
    // RaiseChange commit so the uncontrolled-reseed regression can be asserted.
    internal Task CommitSelectionForTest(TimeSpan time)
    {
        if (EffectiveUse24Hour)
        {
            _hour = time.Hours;
        }
        else
        {
            var h12 = time.Hours % 12;
            _hour = h12 == 0 ? 12 : h12;
            _periodIndex = time.Hours >= 12 ? 1 : 0;
        }
        _minute = SnapMinute(time.Minutes);
        return RaiseChange();
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _resyncPending = false;
            await ScrollColumnsToSelectionAsync();
            ScheduleScrollHandlerEnable();
        }
        else if (_resyncPending)
        {
            // The bound Value changed externally — re-position the columns and
            // suppress the scroll handlers while the programmatic scrolls run
            // (same reasoning as the first-render seeding).
            _resyncPending = false;
            _initialised = false;
            await ScrollColumnsToSelectionAsync();
            ScheduleScrollHandlerEnable();
        }
    }

    private async Task ScrollColumnsToSelectionAsync()
    {
        var hourIdx = _hours.IndexOf(_hour);
        if (hourIdx >= 0) await Interop.WheelScrollTo(_hourCol, hourIdx * ItemHeight);

        var minuteIdx = _minutes.IndexOf(_minute);
        if (minuteIdx >= 0) await Interop.WheelScrollTo(_minuteCol, minuteIdx * ItemHeight);

        if (!EffectiveUse24Hour)
        {
            await Interop.WheelScrollTo(_periodCol, _periodIndex * ItemHeight);
        }
    }

    // 2.2.3: was Task.Delay().ContinueWith(...) — see DateWheelPicker
    // for the rationale. Moves the continuation onto the Blazor sync
    // context so exceptions are observed, not lost on the thread pool.
    private void ScheduleScrollHandlerEnable()
    {
        _ = InvokeAsync(async () =>
        {
            try
            {
                await Task.Delay(150);
                _initialised = true;
            }
            catch (JSDisconnectedException) { /* circuit teardown — fine */ }
        });
    }

    public void Dispose()
    {
        _hourDebounced.Dispose();
        _minuteDebounced.Dispose();
        _periodDebounced.Dispose();
    }
}
